# Re-add branch protection with CI context requirements but no PR review gate
# (AI can still push directly as long as CI passes)
repos = ["elviajero-comercio", "fun4me", "paragu-ai-builder", "base"]

payload = {
    "required_status_checks": {
        "strict": False,
        "contexts": ["ci", "CI", "Deploy"]
    },
    "required_pull_request_reviews": None,
    "enforce_admins": None,
    "restrictions": None
}

for repo in repos:
    r = subprocess.run(["gh", "api", f"repos/Ai-Whisperers/{repo}/branches/main/protection",
                        "--method", "PUT", "--input", "-"],
                       input=json.dumps(payload), capture_output=True, text=True, timeout=30)
    ok = "OK" if r.returncode == 0 else "FAIL"
    print(f"{repo:30s} {ok} {r.stderr[:80]}")
"}
